import java.io.*;import java.util.*;
class Main{static String snap(TreeSet<Integer>s){StringBuilder out=new StringBuilder("[");boolean first=true,open=false;int st=0,prev=0;for(int v:s){if(!open){st=prev=v;open=true;}else if(v==prev+1)prev=v;else{if(!first)out.append(',');first=false;out.append('[').append(st).append(',').append(prev).append(']');st=prev=v;}}if(open){if(!first)out.append(',');out.append('[').append(st).append(',').append(prev).append(']');}return out.append(']').toString();}public static void main(String[]a)throws Exception{String[]d=new String(System.in.readAllBytes()).trim().split("\\s+");if(d.length==1&&d[0].isEmpty())return;int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder all=new StringBuilder();for(int tc=0;tc<t;tc++){int ops=Integer.parseInt(d[idx++]);TreeSet<Integer>seen=new TreeSet<>();ArrayList<String>snaps=new ArrayList<>();for(int i=0;i<ops;i++){String op=d[idx++];if(op.equals("A"))seen.add(Integer.parseInt(d[idx++]));else snaps.add(snap(seen));}if(tc>0)all.append("\n\n");all.append('[').append(String.join(",",snaps)).append(']');}System.out.print(all);}}
